mapper.insert:
INSERT INTO CHAT_ROOM_USER (
seq, room_id, member_id, joined_at, last_read_at
) VALUES (
SEQ_CHAT_ROOM_USER.NEXTVAL, #{room_id}, #{member_id}, SYSDATE, SYSTIMESTAMP
)

choose.when:
SELECT cr.room_id AS "room_id", cr.room_type AS "room_type", cr.festival_id AS "festival_id", cr.owner_id AS "owner_id", NVL(cr.room_title, fi.title || ' 공식 모임') AS "room_title", NVL(cr.room_description, NVL(fi.overview, fi.title || ' 공식 모임방입니다.')) AS "room_description", NVL(cr.free_location, fi.addr1) AS "free_location", NVL(TO_CHAR(cr.free_date, 'YYYY.MM.DD'), fi.event_start_date || ' ~ ' || fi.event_end_date) AS "free_date", NVL(cr.max_capacity, 500) AS "max_capacity",
cr.created_at AS "created_at",
m.nickname AS "nickname", m.profile_image_url AS "profile_image_url", NVL(cr.room_image, fi.first_image) AS "room_image", (SELECT COUNT(*) FROM chat_room_user cru WHERE cru.room_id = cr.room_id) AS "current_count" FROM chat_room cr LEFT JOIN member m ON cr.owner_id = m.member_id LEFT JOIN festival_info fi ON cr.festival_id = fi.content_id WHERE cr.room_id = #{roomId}

mapper.update:
UPDATE CHAT_ROOM
room_title = #{room_title}, room_description = #{room_description}, free_location = #{free_location}, free_date = TO_DATE(#{free_date}, 'YYYY-MM-DD'), max_capacity = #{max_capacity}, room_image = #{room_image}
WHERE room_id = #{room_id}

UPDATE CHAT_ROOM
SET owner_id = #{new_owner_id}
WHERE room_id = #{room_id}

mapper.insert:
INSERT INTO CHAT_ROOM_USER (
seq, room_id, member_id, joined_at, last_read_at
) VALUES (
SEQ_CHAT_ROOM_USER.NEXTVAL, #{room_id}, #{member_id}, SYSDATE, SYSTIMESTAMP
)

mapper.select:
SELECT * FROM ( SELECT ROWNUM AS rnum, res.* FROM ( SELECT NVL(cr.room_id, -fi.content_id) AS "room_id", NVL(LOWER(cr.room_type), 'festival') AS "room_type", fi.content_id AS "festival_id", cr.owner_id AS "owner_id", NVL(cr.room_title, fi.title || ' 공식 모임') AS "room_title", NVL(cr.room_description, fi.title || ' 공식 모임방입니다.') AS "room_description", NVL(cr.free_location, fi.addr1) AS "free_location", fi.event_start_date || ' ~ ' || fi.event_end_date AS "free_date", NVL(cr.max_capacity, 500) AS "max_capacity", cr.created_at AS "created_at", (SELECT COUNT(*) FROM chat_room_user cru WHERE cru.room_id = cr.room_id) AS "current_count", NVL(cr.room_image, fi.first_image) AS "room_image",
(SELECT COUNT(*) FROM chat_room_user WHERE room_id = cr.room_id AND member_id = #{memberId})
0 AS "is_joined" FROM festival_info fi LEFT JOIN chat_room cr ON fi.content_id = cr.festival_id AND cr.room_type = 'FESTIVAL' ORDER BY fi.event_start_date DESC ) res ) WHERE rnum BETWEEN #{startRow} AND #{endRow}
